import{_ as i,o,c as a,a2 as t}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Introduzione","description":"","frontmatter":{},"headers":[],"relativePath":"it/guide/introduction.md","filePath":"it/guide/introduction.md"}'),r={name:"it/guide/introduction.md"};function n(s,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="introduzione" tabindex="-1">Introduzione <a class="header-anchor" href="#introduzione" aria-label="Permalink to &quot;Introduzione&quot;">​</a></h1><h2 id="cos-e-clearance" tabindex="-1">Cos&#39;è Clearance? <a class="header-anchor" href="#cos-e-clearance" aria-label="Permalink to &quot;Cos&#39;è Clearance?&quot;">​</a></h2><p>Clearance è un pannello di amministrazione pronto all&#39;uso per applicazioni Laravel, costruito sopra <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. Aggiunge un pannello Livewire 4 + Flux UI per gestire permessi, ruoli, guardie e impostazioni, oltre a un livello di autorizzazione contestuale e ruoli ceiling - installabile con un solo comando artisan, senza alterare alcuna tabella di Spatie.</p><p>Clearance ti offre:</p><ul><li><strong>Pannello di amministrazione</strong> per Permessi, Ruoli, Guardie, Impostazioni e una Dashboard - usa le route predefinite oppure incorpora ogni componente Livewire singolarmente.</li><li><strong>Autorizzazione contestuale</strong> - concedi un ruolo o un permesso limitato a una specifica istanza di modello (uno Store, un Tenant, un Project), con <code>$user-&gt;canIn()</code>, le direttive Blade <code>@canin</code>/<code>@hasrolein</code>, e un <code>ContextService</code> da usare al di fuori del modello User.</li><li><strong>Ruoli ceiling</strong> - un ruolo può dichiarare un ruolo genitore il cui set di permessi funge da limite superiore; un ruolo figlio non può mai superare il proprio genitore, applicato automaticamente ad ogni salvataggio.</li><li><strong>Permessi di scrittura granulari</strong> - un permesso delegabile <code>clearance-{section}-write</code> per ogni sezione del pannello, così puoi concedere &quot;gestisci ruoli&quot; senza concedere anche &quot;gestisci impostazioni&quot;.</li><li><strong>Super Admin</strong> con un bypass globale del Gate opzionale, rilevamento di alias per ruoli amministrativi già esistenti, e promozione sicura e non distruttiva.</li><li><strong>Modulo Utenti</strong> (opzionale) - assegna ruoli globalmente o a un contesto specifico, oltre a override dei permessi per contesto, da un pannello per singolo utente.</li><li><strong>Pannello Impostazioni</strong> - nome visualizzato, descrizione, icona SVG sanitizzata e colore per ogni ruolo/guardia; un ruolo predefinito configurabile con auto-assegnazione e assegnazione massiva.</li><li><strong>Gestione Guardie</strong> - guardie basate su database, iniettate in <code>auth.guards</code> all&#39;avvio, limitate a un insieme allow-listed di driver.</li><li><strong>9 lingue incluse</strong> (ar, en, es, fr, hi, it, pt, ru, zh), testate per parità di chiavi.</li><li><strong>Hook di estensibilità</strong> - trait <code>HasClearance</code>, trait <code>HasPermissionGroups</code>, contratto <code>ClearanceContextable</code>, componenti Blade riutilizzabili.</li><li><strong>Sanitizzazione SVG</strong> - ogni icona fornita dall&#39;utente passa attraverso un sanitizzatore allow-list prima della memorizzazione e in fase di rendering.</li><li><strong>Sicurezza rafforzata</strong> - limiti ceiling contro l&#39;escalation di privilegi su ogni percorso di concessione dei permessi, override di contesto con priorità al diniego, namespace <code>clearance-*</code> protetto. Vedi <a href="/clearance-docs/it/guide/security.html">Security</a>.</li></ul><h2 id="relazione-con-spatie-laravel-permission" tabindex="-1">Relazione con spatie/laravel-permission <a class="header-anchor" href="#relazione-con-spatie-laravel-permission" aria-label="Permalink to &quot;Relazione con spatie/laravel-permission&quot;">​</a></h2><p>Clearance non è un sostituto del pacchetto di permessi di Spatie - è un livello di UI e autorizzazione costruito sopra di esso. Ruoli e permessi restano i modelli <code>Role</code> e <code>Permission</code> di Spatie, ancora memorizzati nelle tabelle <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> e <code>role_has_permissions</code> di Spatie. Clearance non altera mai quelle tabelle. Tutto ciò che Clearance aggiunge - metadati di visualizzazione, ambito del ruolo, ceiling, assegnazioni contestuali, override per contesto - vive nel proprio insieme di tabelle <code>clr_*</code>. Vedi <a href="/clearance-docs/it/guide/architecture.html">Architecture</a> per il quadro completo.</p><h2 id="requisiti" tabindex="-1">Requisiti <a class="header-anchor" href="#requisiti" aria-label="Permalink to &quot;Requisiti&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dipendenza</th><th>Versione</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="concetti-chiave" tabindex="-1">Concetti chiave <a class="header-anchor" href="#concetti-chiave" aria-label="Permalink to &quot;Concetti chiave&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concetto</th><th>Riepilogo</th></tr></thead><tbody><tr><td>Permesso</td><td>Un permesso Spatie che segue la convenzione di naming <code>group-action</code> (es. <code>orders-create</code>). Concede un&#39;abilità.</td></tr><tr><td>Ambito del ruolo</td><td>Ogni ruolo è <code>global</code> (assegnato direttamente, si applica ovunque) o <code>contextual</code> (legato a tipi di modello specifici, assegnabile solo all&#39;interno di un&#39;istanza di contesto).</td></tr><tr><td>Ruolo ceiling</td><td>Un ruolo può dichiarare un ruolo genitore il cui set di permessi è un limite superiore - il figlio non può mai superarlo.</td></tr><tr><td>Contesto</td><td>Un&#39;istanza di modello (uno Store, un Tenant, un Project) a cui può essere limitato un ruolo o un override di permesso.</td></tr><tr><td>Override</td><td>Una concessione o un diniego di permesso <code>forced_on</code>/<code>forced_off</code> per utente e per contesto - un diniego vince sempre.</td></tr></tbody></table><p>Ognuno di questi concetti ha una pagina dedicata: <a href="/clearance-docs/it/features/permissions.html">Permissions</a>, <a href="/clearance-docs/it/features/roles.html">Roles</a>, <a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a>, <a href="/clearance-docs/it/features/users.html">Users</a>, <a href="/clearance-docs/it/features/super-admin.html">Super Admin</a>.</p><h2 id="prossimi-passi" tabindex="-1">Prossimi passi <a class="header-anchor" href="#prossimi-passi" aria-label="Permalink to &quot;Prossimi passi&quot;">​</a></h2><p>Pronto a installare Clearance? Continua con la <a href="/clearance-docs/it/guide/installation.html">guida all&#39;installazione</a>.</p>',14)])])}const g=i(r,[["render",n]]);export{m as __pageData,g as default};
